import {
	DynamoDBClient,
	GetItemCommand,
} from '@aws-sdk/client-dynamodb';
import { getTenantContext, createResponse } from 'tenant-utils';

const dynamodb = new DynamoDBClient({ region: process.env.AWS_REGION });

const fetchConfig = async (configType, dynamodb, tableNames, tenantId) => {
	const params = {
		TableName: tableNames.configTable,
		Key: {
			id: { S: tenantId },
			configtype: { S: configType },
		},
	};
	const getItemCommand = new GetItemCommand(params);
	const results = await dynamodb.send(getItemCommand);
	console.log(`[Tenant: ${tenantId}] get ${configType} result:`, results);

	if (results.Item === undefined) {
		throw new Error(`No ${configType} found for tenant ${tenantId}`);
	}

	return JSON.parse(results.Item.value.S);
}

export const handler = async (event) => {

	try {
		// Extract tenant context from request
		const tenantContext = await getTenantContext(event);
		console.log('Tenant context:', tenantContext);

		const FeConfig = await fetchConfig('amfaConfigs', dynamodb, tenantContext.tableNames, tenantContext.tenantId);
		const BrandingConfig = await fetchConfig('amfaBrandings', dynamodb, tenantContext.tableNames, tenantContext.tenantId);
		const LegalConfig = await fetchConfig('amfaLegals', dynamodb, tenantContext.tableNames, tenantContext.tenantId);

		// Include recaptcha_key from amfaConfigs in the response for SP portal
		const recaptchaKey = FeConfig?.recaptcha_key || '';

		return createResponse(200, {
			...FeConfig,
			recaptcha_key: recaptchaKey,
			branding: {
				...BrandingConfig,
			},
			legal: {
				...LegalConfig,
			}
		}, tenantContext.tenantId);

	} catch (e) {
		console.log('Catch an error: ', e);
		
		// Try to get tenant ID for error response
		let tenantId = null;
		try {
			const tenantContext = await getTenantContext(event);
			tenantId = tenantContext.tenantId;
		} catch (tenantError) {
			console.log('Could not extract tenant ID for error response:', tenantError.message);
		}
		
		return createResponse(500, { type: 'exception', message: 'Service Error' }, tenantId);
	}

}
